CHAPTERS = [
 {"slug":"ch01-contrato-audiovisual","sub":"CAPÍTULO 1: O Contrato Audiovisual",
  "intro":"Som e imagem não se somam — se transformam mutuamente. Há um contrato tácito em que aceitamos a fusão como percepção única e natural.",
  "cards":[
      {"ic":"link","t":"O Terceiro Sentido","emph":"Terceiro","b":"Você não vê e ouve em faixas isoladas — as duas percepções colidem e se transformam. A imagem altera o que os ouvidos captam, e o som redefine o que os olhos julgam enxergar. Cria-se um <strong>terceiro sentido autônomo</strong>, impossível de ser reduzido à simples soma de ver e ouvir.","tip":"<strong>Como aplicar:</strong> troque a trilha de uma cena e observe como a expressão do ator parece mudar sem que se altere um pixel."},
      {"ic":"pivot","t":"Um Contrato Consentido","emph":"Contrato","b":"A relação entre o áudio e o visual é uma <strong>convenção profunda que você aceita</strong> sem questionar. Não existe adição natural entre as pistas. Se você troca o ruído de cascalho por neve sob os pés do personagem, a mesma imagem instantaneamente vira outra realidade.","tip":"<strong>Modelo mental:</strong> a cena não é um registro fiel da realidade, mas um acordo ilusório de percepção."},
      {"ic":"gap","t":"A Ilusão do Acompanhamento","emph":"Ilusão","b":"Tratar a trilha como uma roupagem opcional de enfeite <strong>ignora que ela redesenha ativamente o que se vê</strong>. Quando você sobrepõe um áudio, a cena original deixa de existir. Analisar os sentidos de forma isolada destrói o coração do fenômeno.","tip":"<strong>Armadilha:</strong> julgar a imagem muda e o som cego quebra a solda que dá sentido à obra.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 1",
  "lessons":["Som e imagem se transformam mutuamente — audiovisão, não soma.","É um contrato: fusão consentida e construída, não natural.","Analisar as partes isoladas perde o fenômeno (a fusão)."]},

 {"slug":"ch02-valor-acrescentado","sub":"CAPÍTULO 2: O Valor Acrescentado",
  "intro":"O conceito mais influente de Chion: o som projeta sentido sobre a imagem de tal forma que o público credita tudo à imagem. O som trabalha; a imagem leva a fama.",
  "cards":[
      {"ic":"eye","t":"A Mágica do Acréscimo","emph":"Acréscimo","b":"O fenômeno ocorre quando a informação do som <strong>enriquece a imagem</strong> a ponto de fundir-se a ela. Você sente como se aquele significado emanasse naturalmente dos pixels na tela. O áudio trabalha nos bastidores para que o vídeo colha os aplausos.","tip":"<strong>Como aplicar:</strong> o som perfeito é invisível — sentido pelo público como propriedade da própria imagem."},
      {"ic":"target","t":"O Som Estrutura o Olhar","emph":"Estrutura","b":"Um texto recitado ou uma trilha impõem para onde seus olhos devem correr. Eles <strong>orientam a atenção</strong> e determinam a leitura definitiva de cenas ambíguas. Mais do que isso, o ritmo sonoro injeta uma sensação cronológica em imagens paradas.","tip":"<strong>Regra:</strong> o som é quem planta o sentido e a emoção; a imagem é quem leva o crédito."},
      {"ic":"gap","t":"O Peso da Redundância","emph":"Redundância","b":"Fazer o áudio gritar exatamente aquilo que a tela já escancara <strong>não acrescenta valor algum</strong> à narrativa. Isso apenas satura os sentidos e rouba o espaço de outras camadas. O bom design sonoro dialoga com a cena em vez de repeti-la como um eco.","tip":"<strong>Cuidado:</strong> mixar um projeto sem testá-lo no mudo esconde a verdadeira função que o som desempenha.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 2",
  "lessons":["Valor acrescentado: o som projeta sentido que o público credita à imagem.","O melhor som é invisível — sentido como propriedade da imagem.","Para medi-lo, tire o som e veja a imagem empobrecer."]},

 {"slug":"ch03-sincrese","sub":"CAPÍTULO 3: A Síncrese",
  "intro":"A soldagem automática entre som e imagem simultâneos. É o fenômeno que torna possível dublagem, foley e efeitos — a mente cola o som ao gesto.",
  "cards":[
      {"ic":"target","t":"A Solda da Síncrese","emph":"Solda","b":"A fusão entre um evento visual e um ruído simultâneo é <strong>involuntária, reflexa e inevitável</strong> no seu cérebro. Você não precisa aprender a juntar as duas coisas — o impacto as cola na hora. É por isso que um soco falso no cinema soa tão doloroso e real.","tip":"<strong>Prática:</strong> você não precisa captar o barulho autêntico no set, mas sim acertar o som no tempo exato."},
      {"ic":"pin","t":"A Força da Sincronia","emph":"Sincronia","b":"Os instantes em que áudio e vídeo colidem com impacto são como <strong>acentos rítmicos</strong> em uma frase falada. Eles pontuam a cena, puxam a atenção e entregam o peso dramático exato. A sincronia tem o poder de unir mundos dispersos numa única pancada.","tip":"<strong>Modelo mental:</strong> a precisão do tempo é o que cola os elementos; a escolha de qual ruído usar fica livre."},
      {"ic":"gap","t":"O Excesso Que Quebra a Magia","emph":"Excesso","b":"Marcar cada passo ou gesto com uma colisão sonora <strong>esgota o espectador e dilui o acento dramático</strong>. É o efeito de desenho animado que retira a gravidade da obra. Quando a sincronia é frouxa ou óbvia demais, a costura se rasga e revela o truque.","tip":"<strong>Sinal de alerta:</strong> sublinhar todos os movimentos é o mesmo que não destacar nenhum.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 3",
  "lessons":["Síncrese: o cérebro solda automaticamente som e imagem simultâneos.","Isso liberta o designer para escolher o som — a sincronia faz o resto.","Synch points são acentos: poderosos quando raros, diluídos quando constantes."]},

 {"slug":"ch04-modos-de-escuta","sub":"CAPÍTULO 4: Os Três Modos de Escuta",
  "intro":"Não escutamos de um jeito só. Cada modo opera diferente — e o designer precisa saber em qual o público está a cada momento.",
  "cards":[
      {"ic":"lens","t":"As Três Lentes Auditivas","emph":"Três Lentes","b":"Você ouve de forma causal para identificar a fonte, escuta pela semântica para decodificar palavras, e usa a escuta reduzida para focar <strong>apenas na textura e altura</strong> do ruído. Cada uma dessas posturas altera a forma como o seu cérebro processa o mundo.","tip":"<strong>Prática:</strong> mixe o seu material garantindo que o modo predominante esteja sempre nítido para quem ouve."},
      {"ic":"key","t":"O Domínio da Escuta Reduzida","emph":"Escuta Reduzida","b":"O mestre do áudio não descreve o barulho de um carro, mas um <strong>zunido grave e áspero que cresce</strong>. Ao se desconectar da origem literal daquele som, você ganha a liberdade de moldá-lo como matéria-prima bruta para evocar novas sensações na tela.","tip":"<strong>Modelo mental:</strong> o público reage pelo significado (causal); o profissional opera pela textura (reduzida)."},
      {"ic":"gap","t":"O Risco do Ambiente Alto","emph":"Ambiente Alto","b":"Ignorar que o foco do público na fala é estritamente <strong>semântico e não de ambiente</strong> faz com que você soterre vozes cruciais sob efeitos sonoros. O ouvinte busca entender a mensagem, e qualquer ruído extra durante o diálogo vira apenas poluição inútil.","tip":"<strong>Armadilha:</strong> deixar o ambiente engolir o texto sabota a única coisa que o espectador deseja ouvir.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 4",
  "lessons":["Três modos: causal (a fonte), semântica (o código/fala), reduzida (o som em si).","Identifique o modo dominante de cada trecho e mixe para ele.","A escuta reduzida é a ferramenta de trabalho do designer."]},

 {"slug":"ch05-acusmatico-acusmetre","sub":"CAPÍTULO 5: O Acusmático e o Acusmêtre",
  "intro":"Um som cuja fonte não se vê é acusmático — e esconder a fonte não é limitação, é poder. A voz sem corpo vira o acusmêtre.",
  "cards":[
      {"ic":"mask","t":"O Poder do Invisível","emph":"Invisível","b":"A voz de origem escondida — o narrador invisível ou o vilão oculto nas sombras — ganha uma aura <strong>onisciente, onipresente e ameaçadora</strong>. Como não está confinada a um rosto específico na tela, a mente assume que ela habita e controla o espaço inteiro.","tip":"<strong>Como aplicar:</strong> preserve a ausência física da maior ameaça para multiplicar o peso psicológico do seu suspense."},
      {"ic":"eye","t":"A Queda Para a Carne","emph":"Queda","b":"A des-acusmatização ocorre no segundo em que você mostra o rosto de quem fala. O corpo <strong>aprisiona aquela entidade</strong> no espaço e no tempo de um simples mortal. A figura perde instantaneamente os seus poderes mágicos e passa a ser apenas humana.","tip":"<strong>Modelo mental:</strong> revelar a origem física do medo é a forma mais eficaz de quebrar o encanto e rebaixar a ameaça."},
      {"ic":"gap","t":"A Revelação Precoce","emph":"Revelação Precoce","b":"Mostrar cedo demais o rosto daquela voz sombria <strong>destrói todo o suspense</strong> que a escuridão sustentava de graça. A expectativa da ameaça no invisível é quase sempre mais aterradora do que o impacto da criatura sob a luz, que termina soando comum.","tip":"<strong>Armadilha:</strong> revelar a figura por ansiedade joga no lixo um dos maiores trunfos da tensão narrativa.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 5",
  "lessons":["Som acusmático = fonte invisível; o invisível aguça a imaginação.","O acusmêtre (voz sem corpo) parece onisciente, onipresente, ameaçador.","Des-acusmatizar (revelar a fonte) drena o poder — use como golpe dramático."]},

 {"slug":"ch06-temporalizacao","sub":"CAPÍTULO 6: A Temporalização",
  "intro":"Uma imagem sozinha é quase atemporal. O som é que dá tempo à imagem: anima, vetoriza e organiza a percepção da duração.",
  "cards":[
      {"ic":"clock","t":"A Injeção do Tempo","emph":"Injeção","b":"O som impõe ao registro visual um <strong>fluxo cronológico palpável</strong> — um presente que não para de escorrer. Sem áudio, a imagem congelada paira na eternidade. Quando o ruído entra, a mesma cena ganha duração contínua, ritmo urgente e um sentido de vida.","tip":"<strong>Regra:</strong> o vídeo entrega a noção de espaço; é o desenho do som que dita a velocidade da experiência."},
      {"ic":"pivot","t":"A Flecha Para o Futuro","emph":"Flecha","b":"Um ruído contínuo ou crescente <strong>aponta a percepção para o que está por vir</strong>. Ele vetoriza o momento, criando uma expectativa incontrolável de clímax ou desfecho. É essa condução que imprime um “antes e depois” incontornável dentro da sua cabeça.","tip":"<strong>Modelo mental:</strong> o áudio é a força propulsora que arrasta a linha do tempo narrativa em direção ao futuro."},
      {"ic":"gap","t":"A Desconexão Letal","emph":"Desconexão Letal","b":"Combinar uma imagem lenta com ruídos que não progridem faz a cena <strong>morrer de inanição</strong>. O espectador sente que nada acontece e o tédio anestesia tudo. Cortar a trilha de forma seca a cada mudança de plano esmaga a ponte que mantém o tempo vivo.","tip":"<strong>Armadilha:</strong> esquecer o progresso sonoro destrói a percepção de que a história está caminhando.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 6",
  "lessons":["O som dá tempo à imagem: temporaliza, vetoriza e anima.","Som que progride cria expectativa — a flecha do tempo da cena.","Som contínuo costura cortes e controla a sensação de duração."]},

 {"slug":"ch07-rendering","sub":"CAPÍTULO 7: O Rendering",
  "intro":"O cinema não reproduz o som real de um evento — busca o som que transmite a sensação esperada dele. Fidelidade à emoção vence fidelidade à física.",
  "cards":[
      {"ic":"spark","t":"A Construção do Rendering","emph":"Rendering","b":"Reproduzir a acústica exata do mundo real não funciona. O audiovisual exige o rendering: a tradução engenhosa de <strong>peso, violência e materialidade</strong> para os ouvidos. Você não grava a ação crua, você esculpe a emoção que aquela gravidade exige.","tip":"<strong>Como aplicar:</strong> molde a camada sonora para replicar a sensação visceral de um impacto, e não a ciência física do barulho."},
      {"ic":"target","t":"O Falso Mais Que Verdadeiro","emph":"Falso","b":"A realidade pura costuma soar <strong>frouxa, fina e insuficiente</strong> no gravador. O barulho de um soco que você acha perfeito foi na verdade construído e exagerado em estúdio. A gravação literal é um rascunho muito pobre diante da experiência que a arte exige.","tip":"<strong>Modelo mental:</strong> o purismo do áudio original é inútil — o que fisga a audiência é o realismo hiperbólico."},
      {"ic":"gap","t":"O Fetiche Pela Verdade","emph":"Fetiche","b":"Insistir na gravação autêntica por uma teimosia documental faz a cena <strong>desabar sem brilho e sem impacto</strong>. Um ruído original fraco parece um erro da produção. O som tímido quebra as promessas dramáticas que a qualidade da fotografia estava fazendo.","tip":"<strong>Armadilha:</strong> confiar no barulho exato da captação garante a honestidade técnica, mas assassina a imersão.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 7",
  "lessons":["Rendering: o som fiel à sensação esperada, não ao som físico real.","O \"real\" costuma decepcionar; a verdade emocional pede construção e exagero.","O irreal convincente entrega mais verdade que o real."]},

 {"slug":"ch08-espacos-vococentrismo","sub":"CAPÍTULO 8: Os Espaços do Som e o Vococentrismo",
  "intro":"Onde o som vive em relação à cena, e por que a voz domina tudo. Três espaços do som, e o vococentrismo que puxa a percepção para a fala.",
  "cards":[
      {"ic":"layers","t":"Os Três Palcos do Som","emph":"Palcos do Som","b":"O áudio transita entre “In” (visto na tela), “Fora de Campo” (diegético na borda) e “Off” (narrador e trilha inalcançáveis). Mover o barulho de um plano invisível para o palco físico <strong>transforma a relação de espaço</strong> sem precisar mover um milímetro de câmera.","tip":"<strong>Como aplicar:</strong> a localização e a reverberação de uma fala entregam tanto significado dramático quanto a palavra dita."},
      {"ic":"target","t":"A Ditadura da Voz","emph":"Voz","b":"O ser humano é biologicamente programado para priorizar a fala <strong>acima de qualquer outra coisa</strong>. Sendo linguagem, os nossos ouvidos buscam obcecadamente o código e o sentido. A dicção humana opera como o sol na cena: todo o resto do ambiente orbita ao seu redor.","tip":"<strong>Regra:</strong> num ecossistema acústico denso, as vozes exigem sempre e de forma absoluta o papel principal."},
      {"ic":"pivot","t":"A Angústia da Indiferença","emph":"Indiferença","b":"Enquanto a trilha empática abraça a dor, a música anempática <strong>segue inabalável enquanto o mundo acaba</strong>. Uma melodia leve durante uma tragédia amplifica o horror silencioso — pois avisa ao espectador que a máquina do universo gira surda e alheia ao seu choro.","tip":"<strong>Sinal de alerta:</strong> competir a fala principal com trilhas emocionais polui o centro das atenções, quebrando a regra de ouro.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 8",
  "lessons":["Três espaços: in (na tela), fora de campo (off diegético), off (não-diegético).","Vococentrismo: a voz e o sentido da fala dominam — protege-se a inteligibilidade.","Empático acompanha; anempático (indiferente) amplifica."]},
]
